        "label": "Example 1",
        "input": "{\n  \"id\": \"go-basics-fmt\",\n  \"title\": \"Formatted I/O with the fmt package (verbs, Sprintf)\",\n  \"difficulty\": \"Easy\",\n  \"tags\": [\"fmt\", \"printf\", \"verbs\", \"formatting\"],\n  \"summary\": \"fmt formats values with verbs: %v general, %d int, %s string, %q quoted, %T type, %+v with field names.\",\n  \"pattern\": \"Verbs\",\n  \"visual\": \"Printf writes to stdout; Sprintf returns the formatted string; each % verb selects a rendering.\",\n  \"memorize\": \"%v value | %+v fields | %#v Go-syntax | %d int | %s str | %q quote | %T type | %p ptr.\",\n  \"scene\": \"The fmt verbs are a printer's tray of stamps: %v inks a plain value, %+v adds field labels, %#v recreates the Go literal, and %T stamps the type name.\",\n  \"time\": \"—\",\n  \"space\": \"—\",\n  \"code\": \"package main\\n\\nimport \\\"fmt\\\"\\n\\ntype Point struct {\\n\\tX, Y int\\n}\\n\\nfunc main() {\\n\\tp := Point{1, 2}\\n\\ts := fmt.Sprintf(\\\"%d-%s\\\", 42, \\\"go\\\")\\n\\n\\tfmt.Printf(\\\"%v\\\\n\\\", p)\\n\\tfmt.Printf(\\\"%+v\\\\n\\\", p)\\n\\tfmt.Printf(\\\"%T %q\\\\n\\\", p, \\\"hi\\\")\\n\\tfmt.Println(s)\\n}\\n\",\n  \"keyPoints\": [\"%v is the general verb; %+v adds struct field names and %#v prints a Go-syntax representation.\", \"Sprintf returns a formatted string instead of printing, while Printf writes to stdout and Println adds spaces and a newline.\", \"%q double-quotes and escapes a string; %T prints the value's dynamic type; %p prints a pointer address.\", \"A wrong verb prints a %!verb(type=...) error string rather than panicking, so go vet flags format mismatches.\"],\n  \"walkthrough\": [\n    {\"title\": \"Build with Sprintf\", \"caption\": \"Sprintf formats %d and %s into a returned string without printing.\", \"focus\": [\"s := fmt.Sprintf(\\\"%d-%s\\\", 42, \\\"go\\\")\"], \"state\": [{\"k\": \"s\", \"v\": \"42-go\"}]},\n    {\"title\": \"Plain %v\", \"caption\": \"%v renders the struct as its bare values inside braces.\", \"focus\": [\"fmt.Printf(\\\"%v\\\\n\\\", p)\"], \"state\": [{\"k\": \"output\", \"v\": \"{1 2}\"}]},\n    {\"title\": \"Labeled %+v\", \"caption\": \"%+v adds the field names to the struct output.\", \"focus\": [\"fmt.Printf(\\\"%+v\\\\n\\\", p)\"], \"state\": [{\"k\": \"output\", \"v\": \"{X:1 Y:2}\"}]},\n    {\"title\": \"Type and quote\", \"caption\": \"%T prints the dynamic type and %q wraps the string in escaped quotes.\", \"focus\": [\"fmt.Printf(\\\"%T %q\\\\n\\\", p, \\\"hi\\\")\"], \"state\": [{\"k\": \"output\", \"v\": \"main.Point \\\"hi\\\"\"}]}\n  ]\n}",
        "output": "4 steps"
