    "cases": [
      {
        "label": "Example 1",
        "input": "{\n  \"id\": \"go-types-conv-vs-assert\",\n  \"title\": \"Type conversion T(x) versus type assertion x.(T)\",\n  \"difficulty\": \"Medium\",\n  \"tags\": [\"conversion\", \"assertion\", \"interface\", \"type-switch\"],\n  \"summary\": \"T(x) reinterprets a concrete value at compile time; x.(T) extracts the dynamic type out of an interface at runtime.\",\n  \"pattern\": \"Convert vs assert\",\n  \"visual\": \"T(x) changes representation between related types; x.(T) unwraps an interface, with comma-ok to avoid a panic.\",\n  \"memorize\": \"T(x) = convert concrete (compile-time). x.(T) = assert interface (runtime, use comma-ok).\",\n  \"scene\": \"Two different doors: conversion relabels a box you already hold, while assertion opens a mystery interface box and checks the contents before trusting them.\",\n  \"time\": \"O(1)\",\n  \"space\": \"O(1)\",\n  \"code\": \"package main\\n\\nimport \\\"fmt\\\"\\n\\nfunc main() {\\n\\tvar i int = 65\\n\\tf := float64(i)\\n\\ts := string(rune(i))\\n\\tfmt.Println(f, s)\\n\\n\\tvar any interface{} = \\\"hello\\\"\\n\\tif str, ok := any.(string); ok {\\n\\t\\tfmt.Println(\\\"string:\\\", str)\\n\\t}\\n\\n\\tif n, ok := any.(int); ok {\\n\\t\\tfmt.Println(\\\"int:\\\", n)\\n\\t} else {\\n\\t\\tfmt.Println(\\\"not an int\\\")\\n\\t}\\n}\\n\",\n  \"keyPoints\": [\"Conversion T(x) works on concrete types with compatible representations and is fully checked at compile time.\", \"Assertion x.(T) applies only to interface values and is resolved at RUNTIME against the stored dynamic type.\", \"The single-result form x.(T) panics on mismatch; the comma-ok form v, ok := x.(T) returns false instead.\", \"string(rune(65)) yields \\\"A\\\", not \\\"65\\\" — converting an int to string reads it as a code point, a notorious trap.\"],\n  \"walkthrough\": [\n    {\"title\": \"Numeric conversion\", \"caption\": \"float64(i) reinterprets the int 65 as 65.0 at compile time.\", \"focus\": [\"f := float64(i)\"], \"state\": [{\"k\": \"f\", \"v\": \"65\"}]},\n    {\"title\": \"int to string gotcha\", \"caption\": \"string(rune(65)) treats 65 as a code point, producing \\\"A\\\" rather than the text \\\"65\\\".\", \"focus\": [\"s := string(rune(i))\"], \"state\": [{\"k\": \"s\", \"v\": \"A\"}]},\n    {\"title\": \"Assert with comma-ok\", \"caption\": \"The interface holds a string, so any.(string) succeeds and ok is true.\", \"focus\": [\"if str, ok := any.(string); ok {\"], \"state\": [{\"k\": \"str\", \"v\": \"hello\"}, {\"k\": \"ok\", \"v\": \"true\"}]},\n    {\"title\": \"Failed assertion\", \"caption\": \"any.(int) fails because the dynamic type is string; comma-ok gives false instead of panicking.\", \"focus\": [\"if n, ok := any.(int); ok {\"], \"state\": [{\"k\": \"ok\", \"v\": \"false\"}, {\"k\": \"output\", \"v\": \"not an int\"}]}\n  ]\n}",
        "output": "4 steps"
      }
    ]
