        "label": "Example 1",
        "input": "{\n  \"id\": \"go-coll-range\",\n  \"title\": \"range over slices, maps, strings, and ints (1.22)\",\n  \"difficulty\": \"Easy\",\n  \"tags\": [\"range\", \"strings\", \"runes\", \"loops\"],\n  \"summary\": \"range yields index/value pairs over slices and maps, decodes runes over strings, and counts 0..n-1 over an int.\",\n  \"pattern\": \"range forms\",\n  \"visual\": \"Slice: i, v. Map: k, v. String: byte-index, rune. Int (1.22): i from 0 to n-1.\",\n  \"memorize\": \"String range = rune + byte offset. range n (1.22) counts 0..n-1. range copies values.\",\n  \"scene\": \"range is a universal turnstile: over a string it clicks per character (rune) but reports the byte gate number, and since 1.22 you can spin it n times with just range n.\",\n  \"time\": \"O(n)\",\n  \"space\": \"O(1)\",\n  \"code\": \"package main\\n\\nimport \\\"fmt\\\"\\n\\nfunc main() {\\n\\tfor i, v := range []string{\\\"a\\\", \\\"b\\\"} {\\n\\t\\tfmt.Println(i, v)\\n\\t}\\n\\n\\tfor i, r := range \\\"hé\\\" {\\n\\t\\tfmt.Println(i, r)\\n\\t}\\n\\n\\ttotal := 0\\n\\tfor i := range 3 {\\n\\t\\ttotal += i\\n\\t}\\n\\tfmt.Println(total)\\n}\\n\",\n  \"keyPoints\": [\"Ranging a string yields the starting BYTE index and a rune (decoded UTF-8), so a multi-byte rune like é makes the next index jump by more than one.\", \"Since Go 1.22, range over an integer n iterates i from 0 to n-1, replacing the classic C-style counting loop.\", \"range hands you a COPY of each value; also since 1.22 the loop variable is fresh per iteration, so closures capturing it no longer share one variable.\"],\n  \"walkthrough\": [\n    {\"title\": \"Range a slice\", \"caption\": \"Over a slice, range yields the index and a copy of each element.\", \"focus\": [\"for i, v := range []string{\\\"a\\\", \\\"b\\\"} {\"], \"state\": [{\"k\": \"output\", \"v\": \"0 a / 1 b\"}]},\n    {\"title\": \"Range a string\", \"caption\": \"Over a string, range decodes runes and reports each rune’s starting byte offset.\", \"focus\": [\"for i, r := range \\\"hé\\\" {\"], \"state\": [{\"k\": \"i, r\", \"v\": \"0 104 / 1 233\"}]},\n    {\"title\": \"Range an int (1.22)\", \"caption\": \"range 3 iterates i = 0, 1, 2, summing to 3.\", \"focus\": [\"for i := range 3 {\"], \"state\": [{\"k\": \"total\", \"v\": \"3\"}]},\n    {\"title\": \"Full output\", \"caption\": \"The three loops print their values in order, ending with the int-range sum.\", \"focus\": [\"fmt.Println(total)\"], \"state\": [{\"k\": \"output\", \"v\": \"0 a / 1 b / 0 104 / 1 233 / 3\"}]}\n  ]\n}",
        "output": "4 steps"
