        "label": "Example 1",
        "input": "{\n  \"id\": \"go-fn-named-returns\",\n  \"title\": \"Named return values and the naked return (and its risk)\",\n  \"difficulty\": \"Medium\",\n  \"tags\": [\"functions\", \"named-returns\", \"naked-return\", \"defer\"],\n  \"summary\": \"Naming return values pre-declares them as zeroed locals so a bare return sends their current state back.\",\n  \"pattern\": \"Named returns\",\n  \"visual\": \"The result names live for the whole body; return with no operands ships whatever they currently hold.\",\n  \"memorize\": \"Named results = pre-zeroed vars; naked return ships them; defer can still mutate them.\",\n  \"scene\": \"Labeled outboxes at a desk: you scribble into \\\"sum\\\" and \\\"err\\\" all day, then a naked return mails whatever is in each box.\",\n  \"time\": \"O(1)\",\n  \"space\": \"O(1)\",\n  \"code\": \"package main\\n\\nimport \\\"fmt\\\"\\n\\nfunc split(sum int) (x, y int) {\\n\\tx = sum * 4 / 9\\n\\ty = sum - x\\n\\treturn\\n}\\n\\nfunc inc() (n int) {\\n\\tdefer func() { n++ }()\\n\\treturn 41\\n}\\n\\nfunc main() {\\n\\ta, b := split(17)\\n\\tfmt.Println(a, b)\\n\\tfmt.Println(\\\"inc:\\\", inc())\\n}\\n\",\n  \"keyPoints\": [\"Named results are declared and zero-valued at function entry; a naked return sends their current values.\", \"A deferred closure can read and MODIFY named results after return runs — return 41 here yields 42.\", \"return 41 assigns 41 to n THEN runs defers, so the mutation is observable — the classic named-return gotcha.\", \"Naked returns aid tiny functions but hurt readability in long ones; the Go team advises restraint.\"],\n  \"walkthrough\": [\n    {\"title\": \"Pre-declared result names\", \"caption\": \"x and y exist as zeroed ints from the first line, so the body assigns into them directly.\", \"focus\": [\"func split(sum int) (x, y int) {\"], \"state\": [{\"k\": \"x\", \"v\": \"0\"}, {\"k\": \"y\", \"v\": \"0\"}]},\n    {\"title\": \"Naked return ships current state\", \"caption\": \"A bare return with no operands sends whatever x and y currently hold.\", \"focus\": [\"return\"], \"state\": [{\"k\": \"x\", \"v\": \"7\"}, {\"k\": \"y\", \"v\": \"10\"}]},\n    {\"title\": \"return assigns the named result\", \"caption\": \"return 41 stores 41 into n before any deferred function runs.\", \"focus\": [\"return 41\"], \"state\": [{\"k\": \"n\", \"v\": \"41\"}]},\n    {\"title\": \"defer mutates after return\", \"caption\": \"The deferred closure increments n after the return value is set, so the caller observes 42.\", \"focus\": [\"defer func() { n++ }()\"], \"state\": [{\"k\": \"n\", \"v\": \"42\"}, {\"k\": \"output\", \"v\": \"inc: 42\"}]}\n  ]\n}",
        "output": "4 steps"
