        "label": "Example 1",
        "input": "{\n  \"id\": \"go-ib-stringer-error\",\n  \"title\": \"Implementing the Stringer and error interfaces\",\n  \"difficulty\": \"Easy\",\n  \"tags\": [\"interfaces\", \"stringer\", \"error\", \"fmt\"],\n  \"summary\": \"Define String() to control %v/Println output and Error() to make a type usable as an error.\",\n  \"pattern\": \"Stringer / error\",\n  \"visual\": \"fmt checks at runtime whether the value implements Stringer or error and calls that method for output.\",\n  \"memorize\": \"String() string => custom print; Error() string => it IS an error.\",\n  \"scene\": \"Two tiny name-tag methods: one tells fmt how to print you, the other tells Go you are a failure worth reporting.\",\n  \"time\": \"O(1)\",\n  \"space\": \"O(1)\",\n  \"code\": \"package main\\n\\nimport \\\"fmt\\\"\\n\\ntype Point struct{ x, y int }\\n\\nfunc (p Point) String() string {\\n\\treturn fmt.Sprintf(\\\"(%d,%d)\\\", p.x, p.y)\\n}\\n\\ntype NotFound struct{ id int }\\n\\nfunc (e NotFound) Error() string {\\n\\treturn fmt.Sprintf(\\\"id %d not found\\\", e.id)\\n}\\n\\nfunc main() {\\n\\tp := Point{1, 2}\\n\\tfmt.Println(p)\\n\\n\\tvar err error = NotFound{id: 7}\\n\\tfmt.Println(err)\\n}\\n\",\n  \"keyPoints\": [\"Implementing String() string satisfies fmt.Stringer, and fmt uses it automatically for %v, %s, and Println.\", \"Implementing Error() string satisfies the built-in error interface, so the type can be returned as an error.\", \"Both interfaces are single-method contracts satisfied implicitly — no explicit registration with fmt or errors.\", \"Beware infinite recursion: calling fmt with %v on the receiver inside String() re-invokes String() forever.\"],\n  \"walkthrough\": [\n    {\"title\": \"Implement Stringer\", \"caption\": \"Point gets String(), so it satisfies fmt.Stringer and controls its own printed form.\", \"focus\": [\"func (p Point) String() string {\"], \"state\": [{\"k\": \"satisfies\", \"v\": \"fmt.Stringer\"}]},\n    {\"title\": \"Println uses String\", \"caption\": \"fmt.Println detects the Stringer and prints (1,2) instead of the default struct dump.\", \"focus\": [\"fmt.Println(p)\"], \"state\": [{\"k\": \"output\", \"v\": \"(1,2)\"}]},\n    {\"title\": \"Implement error\", \"caption\": \"NotFound gets Error(), satisfying the built-in error interface so it can be assigned to an error.\", \"focus\": [\"func (e NotFound) Error() string {\"], \"state\": [{\"k\": \"satisfies\", \"v\": \"error\"}]},\n    {\"title\": \"Print the error\", \"caption\": \"Assigned to an error variable, Println calls Error() to render the message.\", \"focus\": [\"var err error = NotFound{id: 7}\"], \"state\": [{\"k\": \"output\", \"v\": \"id 7 not found\"}]}\n  ]\n}",
