    "cases": [
      {
        "label": "Example 1",
        "input": "{\n  \"id\": \"go-str-runes-bytes\",\n  \"title\": \"Bytes vs runes and UTF-8 encoding\",\n  \"difficulty\": \"Medium\",\n  \"tags\": [\"runes\", \"bytes\", \"utf-8\", \"unicode\"],\n  \"summary\": \"A byte is one uint8 of UTF-8; a rune is an int32 Unicode code point that may span multiple bytes.\",\n  \"pattern\": \"Bytes vs runes\",\n  \"visual\": \"len counts UTF-8 bytes; []rune decodes code points, so multibyte characters shrink the count.\",\n  \"memorize\": \"byte = uint8 (one UTF-8 byte). rune = int32 (one code point). len = bytes, not chars.\",\n  \"scene\": \"A string is a ribbon of bytes; some letters (é, 世) are printed with two or three bytes glued together into one rune.\",\n  \"time\": \"O(n)\",\n  \"space\": \"O(n)\",\n  \"code\": \"package main\\n\\nimport (\\n\\t\\\"fmt\\\"\\n\\t\\\"unicode/utf8\\\"\\n)\\n\\nfunc main() {\\n\\ts := \\\"héllo\\\"\\n\\n\\tfmt.Println(len(s))\\n\\tfmt.Println(utf8.RuneCountInString(s))\\n\\n\\tr := []rune(s)\\n\\tfmt.Println(len(r))\\n\\tfmt.Printf(\\\"%c %d\\\\n\\\", r[1], r[1])\\n}\\n\",\n  \"keyPoints\": [\"byte is an alias for uint8 (one raw UTF-8 byte); rune is an alias for int32 (one Unicode code point).\", \"Go source is UTF-8, so a string literal like \\\"héllo\\\" stores é as two bytes.\", \"len(s) returns the BYTE count; use utf8.RuneCountInString or []rune to count characters — the classic gotcha.\", \"[]rune(s) fully decodes the string into code points, allocating a new int32 slice.\"],\n  \"walkthrough\": [\n    {\"title\": \"Byte length\", \"caption\": \"len counts UTF-8 bytes; é is two bytes so \\\"héllo\\\" is 6 bytes, not 5.\", \"focus\": [\"fmt.Println(len(s))\"], \"state\": [{\"k\": \"len(s)\", \"v\": \"6\"}]},\n    {\"title\": \"Rune count\", \"caption\": \"utf8.RuneCountInString decodes the bytes and counts 5 actual code points.\", \"focus\": [\"utf8.RuneCountInString(s)\"], \"state\": [{\"k\": \"runes\", \"v\": \"5\"}]},\n    {\"title\": \"Decode to runes\", \"caption\": \"[]rune(s) produces a slice of int32 code points; its length is the character count, 5.\", \"focus\": [\"r := []rune(s)\"], \"state\": [{\"k\": \"len(r)\", \"v\": \"5\"}]},\n    {\"title\": \"Inspect one rune\", \"caption\": \"r[1] is é; %c prints the character and %d prints its code point value 233.\", \"focus\": [\"%c %d\"], \"state\": [{\"k\": \"r[1]\", \"v\": \"é (233)\"}]}\n  ]\n}",
        "output": "4 steps"
      }
    ]
