        "label": "Example 1",
        "input": "{\n  \"id\": \"go-str-range\",\n  \"title\": \"Ranging a string decodes runes; indexing yields a byte\",\n  \"difficulty\": \"Medium\",\n  \"tags\": [\"range\", \"runes\", \"strings\", \"utf-8\"],\n  \"summary\": \"for..range over a string yields byte-offset + decoded rune; direct indexing yields a single byte.\",\n  \"pattern\": \"range string\",\n  \"visual\": \"range decodes one UTF-8 rune per step and reports the starting byte index, which can jump by >1.\",\n  \"memorize\": \"range string → (byteIndex, rune). s[i] → byte. Index is a byte offset, not a rune count.\",\n  \"scene\": \"Walking a string with range is stepping stone to stone; a wide stone (multibyte rune) makes the next index leap ahead.\",\n  \"time\": \"O(n)\",\n  \"space\": \"O(1)\",\n  \"code\": \"package main\\n\\nimport \\\"fmt\\\"\\n\\nfunc main() {\\n\\ts := \\\"a世b\\\"\\n\\n\\tfor i, r := range s {\\n\\t\\tfmt.Printf(\\\"%d:%c \\\", i, r)\\n\\t}\\n\\tfmt.Println()\\n\\n\\tfmt.Println(s[1])\\n}\\n\",\n  \"keyPoints\": [\"range over a string yields the starting BYTE index and the decoded rune (int32), not consecutive integers.\", \"The index jumps by the rune width, so a 3-byte rune advances the next index by 3.\", \"Indexing s[i] returns the raw byte at that offset — often a UTF-8 continuation byte, not a character.\", \"Invalid UTF-8 in a range yields the replacement rune U+FFFD without stopping the loop.\"],\n  \"walkthrough\": [\n    {\"title\": \"First rune\", \"caption\": \"At byte index 0 range decodes the single-byte rune a.\", \"focus\": [\"for i, r := range s {\"], \"state\": [{\"k\": \"i\", \"v\": \"0\"}, {\"k\": \"r\", \"v\": \"a\"}]},\n    {\"title\": \"Multibyte rune\", \"caption\": \"世 is three UTF-8 bytes, so it appears at index 1 and the following index leaps to 4.\", \"focus\": [\"%d:%c \"], \"state\": [{\"k\": \"i\", \"v\": \"1\"}, {\"k\": \"r\", \"v\": \"世\"}]},\n    {\"title\": \"Index jumped\", \"caption\": \"The final rune b lands at byte index 4 because 世 consumed indices 1, 2, and 3.\", \"focus\": [\"s := \\\"a世b\\\"\"], \"state\": [{\"k\": \"i\", \"v\": \"4\"}, {\"k\": \"r\", \"v\": \"b\"}]},\n    {\"title\": \"Raw byte indexing\", \"caption\": \"s[1] is the first byte of 世 — a continuation byte 228, not the character itself.\", \"focus\": [\"fmt.Println(s[1])\"], \"state\": [{\"k\": \"s[1]\", \"v\": \"228\"}]}\n  ]\n}",
        "output": "4 steps"
