        "label": "Example 1",
        "input": "{\n  \"id\": \"go-str-strconv\",\n  \"title\": \"Converting numbers and strings with strconv\",\n  \"difficulty\": \"Easy\",\n  \"tags\": [\"strconv\", \"parsing\", \"conversion\"],\n  \"summary\": \"strconv parses and formats numbers; Atoi/Itoa handle base-10 ints and return an error on bad input.\",\n  \"pattern\": \"strconv parse\",\n  \"visual\": \"Atoi parses text to int returning (value, error); Itoa formats an int back to a base-10 string.\",\n  \"memorize\": \"Atoi = ASCII→int, Itoa = int→ASCII. ParseFloat/ParseInt for bases and floats. Always check err.\",\n  \"scene\": \"strconv is the translator booth between the language of digits-as-text and the language of machine numbers.\",\n  \"time\": \"O(n)\",\n  \"space\": \"O(1)\",\n  \"code\": \"package main\\n\\nimport (\\n\\t\\\"fmt\\\"\\n\\t\\\"strconv\\\"\\n)\\n\\nfunc main() {\\n\\tn, err := strconv.Atoi(\\\"42\\\")\\n\\tfmt.Println(n, err)\\n\\n\\t_, err = strconv.Atoi(\\\"4x\\\")\\n\\tfmt.Println(err != nil)\\n\\n\\ts := strconv.Itoa(n * 2)\\n\\tf, _ := strconv.ParseFloat(\\\"3.5\\\", 64)\\n\\tfmt.Println(s, f)\\n}\\n\",\n  \"keyPoints\": [\"strconv.Atoi(s) parses a base-10 string and returns (int, error) — always check the error.\", \"strconv.Itoa(n) is the reverse, formatting an int as a base-10 string with no error.\", \"ParseInt and ParseFloat take an explicit base and bit size for wider control (e.g. ParseInt(s, 16, 64)).\", \"The gotcha: string(65) is NOT \\\"65\\\" — it yields the rune \\\"A\\\"; use strconv.Itoa to stringify a number.\"],\n  \"walkthrough\": [\n    {\"title\": \"Parse a valid int\", \"caption\": \"Atoi(\\\"42\\\") returns the int 42 and a nil error.\", \"focus\": [\"strconv.Atoi(\\\"42\\\")\"], \"state\": [{\"k\": \"n\", \"v\": \"42\"}, {\"k\": \"err\", \"v\": \"<nil>\"}]},\n    {\"title\": \"Handle bad input\", \"caption\": \"Atoi(\\\"4x\\\") cannot parse, so it returns 0 and a non-nil *NumError; err != nil is true.\", \"focus\": [\"strconv.Atoi(\\\"4x\\\")\"], \"state\": [{\"k\": \"err != nil\", \"v\": \"true\"}]},\n    {\"title\": \"Format back to string\", \"caption\": \"Itoa turns 84 (n*2) into the string \\\"84\\\".\", \"focus\": [\"strconv.Itoa(n * 2)\"], \"state\": [{\"k\": \"s\", \"v\": \"84\"}]},\n    {\"title\": \"Parse a float\", \"caption\": \"ParseFloat(\\\"3.5\\\", 64) yields the float64 value 3.5.\", \"focus\": [\"strconv.ParseFloat(\\\"3.5\\\", 64)\"], \"state\": [{\"k\": \"f\", \"v\": \"3.5\"}]}\n  ]\n}",
