        "label": "Example 1",
        "input": "{\n  \"id\": \"go-str-ops\",\n  \"title\": \"Common strings package operations (Split, Join, Fields, TrimSpace)\",\n  \"difficulty\": \"Easy\",\n  \"tags\": [\"strings\", \"split\", \"join\", \"fields\"],\n  \"summary\": \"The strings package covers everyday text work: Split, Join, Fields, TrimSpace, Contains, and more.\",\n  \"pattern\": \"strings ops\",\n  \"visual\": \"Split cuts on a separator; Fields splits on runs of whitespace; Join glues a slice; TrimSpace strips edges.\",\n  \"memorize\": \"Split(sep) keeps empties; Fields splits on whitespace and drops empties; Join is Split reversed.\",\n  \"scene\": \"A text toolbox: scissors (Split/Fields), glue (Join), and an eraser for the margins (TrimSpace).\",\n  \"time\": \"O(n)\",\n  \"space\": \"O(n)\",\n  \"code\": \"package main\\n\\nimport (\\n\\t\\\"fmt\\\"\\n\\t\\\"strings\\\"\\n)\\n\\nfunc main() {\\n\\tparts := strings.Split(\\\"a,b,c\\\", \\\",\\\")\\n\\tfmt.Println(parts, len(parts))\\n\\n\\tfmt.Println(strings.Join(parts, \\\"-\\\"))\\n\\tfmt.Println(strings.Fields(\\\"  x   y \\\"))\\n\\tfmt.Printf(\\\"%q\\\\n\\\", strings.TrimSpace(\\\"  hi \\\\n\\\"))\\n\\tfmt.Println(strings.Contains(\\\"golang\\\", \\\"lang\\\"))\\n}\\n\",\n  \"keyPoints\": [\"Split(s, sep) cuts on every separator and KEEPS empty substrings between adjacent separators.\", \"Fields(s) splits on runs of Unicode whitespace and drops empties — ideal for tokenizing free-form input.\", \"Join(slice, sep) is the inverse of Split, concatenating with the separator between elements.\", \"TrimSpace strips leading and trailing whitespace only; Contains reports substring presence as a bool.\"],\n  \"walkthrough\": [\n    {\"title\": \"Split on a separator\", \"caption\": \"Split(\\\"a,b,c\\\", \\\",\\\") returns a 3-element slice [a b c].\", \"focus\": [\"strings.Split(\\\"a,b,c\\\", \\\",\\\")\"], \"state\": [{\"k\": \"parts\", \"v\": \"[a b c]\"}, {\"k\": \"len\", \"v\": \"3\"}]},\n    {\"title\": \"Join a slice\", \"caption\": \"Join glues the parts back with \\\"-\\\" to produce \\\"a-b-c\\\".\", \"focus\": [\"strings.Join(parts, \\\"-\\\")\"], \"state\": [{\"k\": \"joined\", \"v\": \"a-b-c\"}]},\n    {\"title\": \"Split on whitespace\", \"caption\": \"Fields collapses runs of spaces and drops empties, returning [x y].\", \"focus\": [\"strings.Fields(\\\"  x   y \\\")\"], \"state\": [{\"k\": \"fields\", \"v\": \"[x y]\"}]},\n    {\"title\": \"Trim and test\", \"caption\": \"TrimSpace strips surrounding whitespace to \\\"hi\\\"; Contains confirms \\\"lang\\\" is inside \\\"golang\\\".\", \"focus\": [\"strings.TrimSpace(\\\"  hi \\\\n\\\")\"], \"state\": [{\"k\": \"trimmed\", \"v\": \"\\\"hi\\\"\"}, {\"k\": \"contains\", \"v\": \"true\"}]}\n  ]\n}",
