    "cases": [
      {
        "label": "Example 1",
        "input": "{\n  \"id\": \"go-gen-inference\",\n  \"title\": \"Type inference & its limits\",\n  \"difficulty\": \"Hard\",\n  \"tags\": [\"generics\", \"type-inference\", \"type-parameters\", \"go1.26\"],\n  \"summary\": \"How Go infers type arguments from function args, and the hard limits where you must be explicit.\",\n  \"pattern\": \"Type inference\",\n  \"visual\": \"Args flow into type params; return position and methods never feed inference.\",\n  \"memorize\": \"Inference reads arguments, never the return; methods get no type params.\",\n  \"scene\": \"A funnel that only accepts liquid poured from the top (arguments); the spout (return type) can never push liquid back up to fill it.\",\n  \"time\": \"O(1)\",\n  \"space\": \"O(1)\",\n  \"code\": \"package main\\n\\nimport \\\"fmt\\\"\\n\\n// Map infers T and U from the slice and function arguments.\\nfunc Map[T, U any](in []T, f func(T) U) []U {\\n\\tout := make([]U, len(in))\\n\\tfor i, v := range in {\\n\\t\\tout[i] = f(v)\\n\\t}\\n\\treturn out\\n}\\n\\n// Parse cannot infer T from context: its only type-param use is the\\n// return type, so callers must supply T explicitly.\\nfunc Parse[T any](s string) (T, error) {\\n\\tvar zero T\\n\\treturn zero, fmt.Errorf(\\\"cannot parse %q\\\", s)\\n}\\n\\nfunc main() {\\n\\tnums := []int{1, 2, 3}\\n\\t// T=int inferred from nums; U=string inferred from the func literal.\\n\\tstrs := Map(nums, func(n int) string { return fmt.Sprintf(\\\"#%d\\\", n) })\\n\\tfmt.Println(strs)\\n\\n\\t// No inference from return position: T must be given explicitly.\\n\\tv, err := Parse[int](\\\"42\\\")\\n\\tfmt.Println(v, err)\\n}\\n\",\n  \"keyPoints\": [\"Type inference uses ordinary function arguments (including their element/function-signature structure), never the return type or the assignment/LHS context.\", \"A type parameter appearing only in the result is un-inferable — callers must always pass it explicitly.\", \"Go has no partial-then-infer for the remaining params from context: if a param can't be inferred from args, supplying the others doesn't help.\", \"Methods may not declare their own type parameters (\\\"method must have no type parameters\\\"); put the parameter on the enclosing type.\", \"Untyped constant arguments infer to their default type (3 -> int); untyped nil carries no type and cannot drive inference — use a typed nil.\", \"Idiomatic fix for return-only generics: take a destination pointer (json.Unmarshal style) so T is inferred from the argument.\"],\n  \"walkthrough\": [\n    {\"title\": \"Generic Map declared\", \"caption\": \"Map is defined with two type parameters T and U that the compiler will later fill in from the call site, not from any annotation.\", \"focus\": [\"func Map[T, U any](in []T, f func(T) U) []U\"], \"state\": [{\"k\": \"T\", \"v\": \"unbound\"}, {\"k\": \"U\", \"v\": \"unbound\"}]},\n    {\"title\": \"Parse declared (return-only T)\", \"caption\": \"Parse uses its type parameter T only in the return type, so nothing at a call site can pin it down by argument inference.\", \"focus\": [\"func Parse[T any](s string) (T, error)\"], \"state\": [{\"k\": \"T uses\", \"v\": \"return only\"}, {\"k\": \"inferable\", \"v\": \"no\"}]},\n    {\"title\": \"Build the input slice\", \"caption\": \"main starts and constructs a concrete []int, which will drive inference for the Map call below.\", \"focus\": [\"nums := []int{1, 2, 3}\"], \"state\": [{\"k\": \"nums\", \"v\": \"[1 2 3]\"}, {\"k\": \"type(nums)\", \"v\": \"[]int\"}]},\n    {\"title\": \"Infer T from the slice\", \"caption\": \"Passing nums to Map's in []T unifies []T with []int, so the compiler infers T=int purely from the argument.\", \"focus\": [\"Map(nums,\", \"in []T\"], \"state\": [{\"k\": \"T\", \"v\": \"int\"}, {\"k\": \"U\", \"v\": \"unbound\"}]},\n    {\"title\": \"Infer U from the func literal\", \"caption\": \"The func(int) string literal unifies with f func(T) U, fixing U=string; inference reads the arguments, never the []U return.\", \"focus\": [\"func(n int) string { return fmt.Sprintf(\\\"#%d\\\", n) }\", \"f func(T) U\"], \"state\": [{\"k\": \"T\", \"v\": \"int\"}, {\"k\": \"U\", \"v\": \"string\"}]},\n    {\"title\": \"Map runs elementwise\", \"caption\": \"With T and U resolved, Map allocates a []string of len 3 and applies f to each element, producing the mapped slice.\", \"focus\": [\"out := make([]U, len(in))\", \"out[i] = f(v)\"], \"state\": [{\"k\": \"out\", \"v\": \"[#1 #2 #3]\"}, {\"k\": \"len/cap\", \"v\": \"3/3\"}, {\"k\": \"strs\", \"v\": \"[#1 #2 #3]\"}]},\n    {\"title\": \"The inference limit\", \"caption\": \"Calling Parse the same inference-free way would fail because T appears only in the return, so T=int must be written explicitly.\", \"focus\": [\"Parse[int](\\\"42\\\")\"], \"state\": [{\"k\": \"T\", \"v\": \"int (explicit)\"}, {\"k\": \"inferred?\", \"v\": \"no\"}]},\n    {\"title\": \"Parse returns the zero value\", \"caption\": \"Parse yields the zero value of the explicit T plus an error, showing why the caller had to supply the type argument.\", \"focus\": [\"var zero T\", \"return zero, fmt.Errorf(\\\"cannot parse %q\\\", s)\"], \"state\": [{\"k\": \"v\", \"v\": \"0\"}, {\"k\": \"err\", \"v\": \"cannot parse \\\"42\\\"\"}]}\n  ]\n}",
        "output": "8 steps"
      }
    ]
