    "cases": [
      {
        "label": "Example 1",
        "input": "{\n  \"id\": \"go-conc-scheduler\",\n  \"title\": \"Goroutines & the GMP scheduler\",\n  \"difficulty\": \"Hard\",\n  \"tags\": [\"concurrency\", \"runtime\", \"scheduler\", \"goroutines\", \"GMP\"],\n  \"summary\": \"How Go's M:N scheduler multiplexes millions of goroutines onto OS threads.\",\n  \"pattern\": \"GMP scheduler\",\n  \"visual\": \"G (goroutines) sit in P-local runqueues; each P binds one M (OS thread) to run them, stealing work when idle.\",\n  \"memorize\": \"G on P on M; GOMAXPROCS caps P; idle P steals half; async preempt via SIGURG at safe points.\",\n  \"scene\": \"Picture 4 chefs (M) each holding one cutting board (P) with a stack of orders (G); an idle chef grabs half the orders off a busy chef's board.\",\n  \"time\": \"—\",\n  \"space\": \"O(1) stack ~2KB per G\",\n  \"code\": \"package main\\n\\nimport (\\n\\t\\\"fmt\\\"\\n\\t\\\"runtime\\\"\\n\\t\\\"sync\\\"\\n\\t\\\"sync/atomic\\\"\\n)\\n\\nfunc main() {\\n\\tprev := runtime.GOMAXPROCS(4)\\n\\tfmt.Printf(\\\"logical CPUs=%d, previous GOMAXPROCS=%d\\\\n\\\", runtime.NumCPU(), prev)\\n\\n\\tvar completed atomic.Int64\\n\\tconst goroutines = 100_000\\n\\n\\tvar wg sync.WaitGroup\\n\\twg.Add(goroutines)\\n\\tfor i := 0; i < goroutines; i++ {\\n\\t\\tgo func(n int) {\\n\\t\\t\\tdefer wg.Done()\\n\\t\\t\\tsum := 0\\n\\t\\t\\tfor j := 0; j < n%64; j++ {\\n\\t\\t\\t\\tsum += j\\n\\t\\t\\t}\\n\\t\\t\\tif sum >= 0 {\\n\\t\\t\\t\\tcompleted.Add(1)\\n\\t\\t\\t}\\n\\t\\t}(i)\\n\\t}\\n\\n\\twg.Wait()\\n\\tfmt.Printf(\\\"spawned=%d completed=%d maxGoroutines=%d\\\\n\\\",\\n\\t\\tgoroutines, completed.Load(), runtime.NumGoroutine())\\n}\\n\",\n  \"keyPoints\": [\"GMP: G=goroutine, M=OS thread, P=scheduling context; GOMAXPROCS sets the number of P's, capping parallel execution of Go code.\", \"Goroutines are cheap because they use small (~2KB) growable stacks and are multiplexed in user space, avoiding kernel context-switch cost.\", \"Blocking on a channel/mutex parks the G and frees M+P; a raw blocking syscall blocks the M itself and triggers a P handoff to another M.\", \"Work-stealing keeps P's busy: an idle P checks the global queue and netpoller, then steals ~half of a random victim P's local runqueue.\", \"Asynchronous (SIGURG-based) preemption since Go 1.14 interrupts call-free tight loops at safe points, preventing P starvation.\", \"GOMAXPROCS is cgroup-aware by default in Go 1.25+, but pin it explicitly to the CPU quota in containers to avoid preemption-driven tail latency.\"],\n  \"walkthrough\": [\n    {\"title\": \"Cap the P count\", \"caption\": \"GOMAXPROCS(4) sets the number of logical processors (P) to 4, returning the previous value, so at most 4 goroutines run Go code simultaneously.\", \"focus\": [\"prev := runtime.GOMAXPROCS(4)\"], \"state\": [{\"k\": \"GOMAXPROCS (P)\", \"v\": \"4\"}, {\"k\": \"prev\", \"v\": \"old value\"}]},\n    {\"title\": \"Report the machine\", \"caption\": \"NumCPU reports the number of logical CPUs usable by the current process, which is independent of the GOMAXPROCS cap we just set.\", \"focus\": [\"runtime.NumCPU()\", \"previous GOMAXPROCS=%d\"], \"state\": [{\"k\": \"P\", \"v\": \"4\"}, {\"k\": \"NumCPU\", \"v\": \"host-dependent\"}]},\n    {\"title\": \"Arm the barrier\", \"caption\": \"WaitGroup counter is set to 100,000 up front so main can later block until every spawned goroutine calls Done.\", \"focus\": [\"const goroutines = 100_000\", \"wg.Add(goroutines)\"], \"state\": [{\"k\": \"wg counter\", \"v\": \"100000\"}, {\"k\": \"completed\", \"v\": \"0\"}]},\n    {\"title\": \"Spawn 100k G's\", \"caption\": \"Each 'go' creates a lightweight goroutine (starting ~2KB stack) queued onto a P's local run queue, far exceeding the 4 P's so most G's wait runnable.\", \"focus\": [\"go func(n int) {\", \"}(i)\"], \"state\": [{\"k\": \"goroutines created\", \"v\": \"up to 100000\"}, {\"k\": \"P\", \"v\": \"4\"}, {\"k\": \"running G's\", \"v\": \"<= 4\"}, {\"k\": \"stack/G\", \"v\": \"~2KB\"}]},\n    {\"title\": \"Scheduled onto M\", \"caption\": \"A runnable G is bound to a P and executed on an M (OS thread); when a P's local queue empties, an idle P steals half the runnable G's from another P's queue.\", \"focus\": [\"sum := 0\", \"sum += j\"], \"state\": [{\"k\": \"G on P on M\", \"v\": \"active\"}, {\"k\": \"idle P\", \"v\": \"steals half\"}, {\"k\": \"work stealing\", \"v\": \"on\"}]},\n    {\"title\": \"Async preemption\", \"caption\": \"The tight for loop is preemptible: the sysmon thread signals long-running G's with SIGURG so the scheduler can preempt at an async-safe point and give other G's a turn.\", \"focus\": [\"for j := 0; j < n%64; j++ {\"], \"state\": [{\"k\": \"preempt signal\", \"v\": \"SIGURG\"}, {\"k\": \"trigger\", \"v\": \">10ms on P\"}, {\"k\": \"time slice\", \"v\": \"~10ms\"}]},\n    {\"title\": \"Atomic completion\", \"caption\": \"completed.Add(1) is a lock-free atomic increment, so 100,000 concurrent G's can record completion without a mutex or data race.\", \"focus\": [\"completed.Add(1)\", \"defer wg.Done()\"], \"state\": [{\"k\": \"completed\", \"v\": \"-> 100000\"}, {\"k\": \"wg counter\", \"v\": \"-> 0\"}, {\"k\": \"sync\", \"v\": \"atomic (lock-free)\"}]},\n    {\"title\": \"Join and report\", \"caption\": \"wg.Wait parks main until the counter hits zero, then NumGoroutine reflects the drained population (near 1 plus runtime helpers) since the workers have exited.\", \"focus\": [\"wg.Wait()\", \"runtime.NumGoroutine()\"], \"state\": [{\"k\": \"wg counter\", \"v\": \"0\"}, {\"k\": \"completed.Load()\", \"v\": \"100000\"}, {\"k\": \"live goroutines\", \"v\": \"~1\"}]}\n  ]\n}",
        "output": "8 steps"
      }
    ]
